class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7

        # dp[i][j] = number of ways to build a sequence with i zeros and j ones
        # such that the last element is 0 if i > 0, or 1 if j > 0
        dp = [[0] * (one + 1) for _ in range(zero + 1)]

        # Initialize base cases
        dp[0][0] = 1  # empty sequence

        for i in range(zero + 1):
            for j in range(one + 1):
                if i == 0 and j == 0:
                    continue
                if i > 0:
                    # Add a 0 to sequences ending with 0 or 1
                    # Ensure that the last 'limit' elements do not consist of only 0s
                    if i - 1 >= 0:
                        for k in range(1, limit + 1):
                            if j >= k:
                                dp[i][j] = (dp[i][j] + dp[i - k][j]) % MOD
                if j > 0:
                    # Add a 1 to sequences ending with 0 or 1
                    # Ensure that the last 'limit' elements do not consist of only 1s
                    if j - 1 >= 0:
                        for k in range(1, limit + 1):
                            if i >= k:
                                dp[i][j] = (dp[i][j] + dp[i][j - k]) % MOD

        return dp[zero][one]
